const cache = new WeakMap();
function cacheData(obj) {
  if (!cache.has(obj)) {
    cache.set(obj, { data: 'Some cached info' });
  }
  return cache.get(obj);
}

let user = { name: 'Alice' };
cacheData(user);
user = null; // Now 'user' and its cache can be garbage collected

